VALUES
  ('social-worker-moex-01641', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當一個人擁有部分證據時，便假定這份證據也可以應用在其他各種情境，這是犯了下列何種錯誤？', '["選擇性觀察", "過度推論", "科學推論", "月暈效應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01642', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某公司的人資部門邀請學者進行研究，發現員工協助方案確實可以提高員工生產力，此研究是屬 於下列那一種類型？', '["探索性研究", "描述性研究", "解釋性研究", "預測性研究"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01643', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一項社會態度的調查研究，首次以全臺灣20歲的年輕人為對象，抽取1500位樣本進行抽樣調查， 每隔五年依序調查25、30、35、40歲的人，以比較其社會態度的變化，持續5次，資料蒐集期 間長達20年。請問這項研究屬於下列何種類型？', '["橫斷性研究（cross-sectional study）", "趨勢研究（trend study）", "世代研究（cohort study）", "固定樣本連續研究（panel study）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01644', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某社工訪談了30位高關懷少年，發現這些人若有老師或其他正向成人的關心，比較不會出現偏 差行為，因此認為正向社會支持能夠降低少年的風險行為，這是何種推理過程？', '["歸納法", "否證法", "演繹法", "辯證法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01645', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '行動研究法常運用三角檢核法（triangulation）來蒐集資料，下列何者不是三角檢核之一？', '["不同資料來源：報紙、官方文件、會議紀錄", "不同蒐集資料方法：如訪談、觀察、文件蒐集", "不同情境：家裡、學校、公園", "不同觀察者：案主、家人、社工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01646', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關科學典範（paradigm）的敘述，何者正確？', '["實證科學典範認為世界上沒有絕對的真實，所以需要靠科學家持續的探究", "詮釋論典範認為世界上有唯一的真理，但必須靠互相建構意義方能發現真理", "批判論典範忽略權力結構與衝突的意義，認為必須以歷史與辯證的方法發現真實", "詮釋論典範與社會建構論很類似，也相當重視主觀性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01647', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關以律則式（nomothetic）模式解釋因果關係，下列敘述何者正確？', '["律則式模式使用相關且較多的變項，對特定現象獲得深度的認識", "律則式模式解釋因果關係時，是立基於或然率的高低", "律則式模式的目標是透過列舉特定現象背後的眾多原因，有些甚至可能是很獨特的原因", "律則式模式想了解年輕人為何會犯罪，會儘可能完整地了解這個人所有的特質傾向"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01648', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在質化研究中，研究者通常不會在研究前給予變項的操作性定義，下列理由何者錯誤？', '["研究者通常無法在研究前就知道現象的重要意義與內容是什麼", "對於現象的了解有限，因此無法做出好的操作性定義", "操作性定義無法給予研究者更深入了解觀察事物的意義", "研究者通常在研究前就對現象一無所知，所以無從給予操作性定義"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01649', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '「當控制了C變項後，原先A變項與B變項間的正向關係就消失了」，原本A與B二變項的正 相關是屬於下列何種關係？', '["因果關係", "真實關係", "虛假關係", "非虛假關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01650', 'social-worker', 'social-worker-moex-108-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '「人的壽命都有限，陳先生是人，所以陳先生的壽命有限」，這是何種推論過程？', '["辯證法", "相關法", "歸納法", "演繹法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "e5b3fcc5b890", "answer_pdf_sha1": "6aeaee821afc", "source_family": "moex-gov-tw", "moex": {"exam_code": "108020", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "108", "exam_name": "108年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
